------------------------------------------------------------
----- TRIGGER FOR __mj_UpdatedAt field for the commerce_payments table
------------------------------------------------------------
IF OBJECT_ID('[hubspot].[trgUpdatecommerce_payments]', 'TR') IS NOT NULL
    DROP TRIGGER [hubspot].[trgUpdatecommerce_payments];
GO
CREATE TRIGGER [hubspot].trgUpdatecommerce_payments
ON [hubspot].[commerce_payments]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE
        [hubspot].[commerce_payments]
    SET
        __mj_UpdatedAt = GETUTCDATE()
    FROM
        [hubspot].[commerce_payments] AS _organicTable
    INNER JOIN
        INSERTED AS I ON
        _organicTable.[hs_object_id] = I.[hs_object_id];
END;
GO
        